url = "https://api-staging.craftmypdf.com/v1/update-pdf-fields"
headers = {
    "x-api-key": "xxxxx",
    "Content-Type": "application/json"
}
payload = {
    "url": "https://craftmypdf.s3.ap-southeast-1.amazonaws.com/test/output+-+2025-01-24T170834.623.pdf",
    "fields": [
        {"id": "optionlist_1", "value": "Gaming", "readOnly": False},
        {"id": "email", "value": "willxxxx@craftmypdf.com", "readOnly": True},
        {"id": "checkbox_1", "value": False, "readOnly": False},
        {"id": "last_name", "value": "Smith", "readOnly": False},
        {"id": "first_name", "value": "Will", "readOnly": False},
        {"id": "dropdown_1", "value": "v1", "readOnly": False},
